use serde_json::json;

use super::{ManifestMethod, RenderedManifest};

pub fn build_manifest(contract_name: &str, methods: &[ManifestMethod]) -> RenderedManifest {
    let manifest = json!({
        "name": contract_name,
        "groups": [],
        "features": {},
        "supportedstandards": [],
        "permissions": [],
        "trusts": [],
        "abi": {
            "methods": methods,
            "events": [],
        },
        "extra": {
            "author": "R3E Network",
            "description": "Generated by wasm-neovm translator",
        }
    });

    RenderedManifest { value: manifest }
}
